#include <bits/stdc++.h>
using namespace std;

int to_decimal(const string& s, int base) {
    int val = 0;
    for (char c : s) {
        val = val * base + (c - '0');
    }
    return val;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string bin, ter;
    cin >> bin >> ter;

    // Try all single-digit flips in binary string
    for (int i = 0; i < (int)bin.size(); i++) {
        string b2 = bin;
        for (char d = '0'; d <= '1'; d++) {
            if (d == bin[i]) continue;
            b2[i] = d;
            // Leading zero allowed? The problem says yes, it can be '0' mistakenly.
            // So we don't skip leading zeros.
            int val2 = to_decimal(b2, 2);

            // Now try all single-digit flips in ternary string
            for (int j = 0; j < (int)ter.size(); j++) {
                string t3 = ter;
                for (char e = '0'; e <= '2'; e++) {
                    if (e == ter[j]) continue;
                    t3[j] = e;
                    int val3 = to_decimal(t3, 3);
                    if (val2 == val3 && val2 >= 1) {
                        cout << val2 << '\n';
                        return 0;
                    }
                }
            }
        }
    }

    // Should never reach here per problem guarantee
    return 0;
}
